import{_ as t,C as r,o as n,c as b,af as a,E as i,j as l,a as o}from"./chunks/framework.DuHE0XFB.js";const x=JSON.parse('{"title":"2008 骑行川藏南线","description":"","frontmatter":{"title":"2008 骑行川藏南线","date":"2020-02-07T02:01:23.000Z"},"headers":[],"relativePath":"posts/biketotibet.md","filePath":"posts/biketotibet.md"}'),u={name:"posts/biketotibet.md"};function s(p,e,m,k,T,P){const d=r("ImageGallery");return n(),b("div",null,[e[0]||(e[0]=a("",4)),i(d,{dir:"/images/biketotibet/20080502/"}),e[1]||(e[1]=a("",3)),i(d,{dir:"/images/biketotibet/20080503/"}),e[2]||(e[2]=l("h2",{id:"🌤-沿青衣江到达天全县两路乡-5月4日",tabindex:"-1"},[o("🌤 沿青衣江到达天全县两路乡（5月4日） "),l("a",{class:"header-anchor",href:"#🌤-沿青衣江到达天全县两路乡-5月4日","aria-label":'Permalink to "🌤 沿青衣江到达天全县两路乡（5月4日）"'},"​")],-1)),e[3]||(e[3]=l("p",null,[l("code",null,"天全县"),o(),l("code",null,"两路乡"),o(),l("code",null,"顶风爬坡"),o(),l("code",null,"文家饭店")],-1)),e[4]||(e[4]=l("p",null,"今天早上从雅安出发后便进入山路，不停的上下坡，而且一路顶风，为了减少阻力我们轮着领骑，这样能相对减少体力消耗，山里很凉快，景色也很好，山下的青衣江由灰色变成黄色最后又变成灰色，路边有很多大狗，我们路过时他们就会狂叫，很吓人，最吓人的还是那些躲在角落里的狗，总是会突然跳出来，不过好在他们都被拴着，上午在路边看到一个当地人在接山泉水，她说她们家从很久以前就一直喝这个，还说水特好，于是我也接了一瓶，虽然有点甜但是特别凉，晚上快六点时我们到达天全县的两路乡，住在“文家饭店”，文家饭店是个3层的大院，对面是公安局，隔壁是乡政府，住这放心，而且才十元一人，这家店的老板娘在天全县的厨艺比赛中还得过一等奖，晚上我们点了个砂锅豆腐，锅里除了豆腐还有好几种蘑菇，还有肥肠，丸子，肉，香肠等，味道很好，今天爬了一天山，有好几次都觉得自己不行了想下来推会，但都坚持过来了，其实很多事都是这样，一咬牙就过去了。",-1)),i(d,{dir:"/images/biketotibet/20080504/"}),e[5]||(e[5]=a("",3)),i(d,{dir:"/images/biketotibet/20080505/"}),e[6]||(e[6]=a("",3)),i(d,{dir:"/images/biketotibet/20080506/"}),e[7]||(e[7]=l("h2",{id:"🌧-在康定休息-5月7日",tabindex:"-1"},[o("🌧 在康定休息（5月7日） "),l("a",{class:"header-anchor",href:"#🌧-在康定休息-5月7日","aria-label":'Permalink to "🌧 在康定休息（5月7日）"'},"​")],-1)),e[8]||(e[8]=l("p",null,[l("code",null,"休息"),o(),l("code",null,"丁大姐牛杂汤"),o(),l("code",null,"葡萄糖"),o(),l("code",null,"红糖水")],-1)),e[9]||(e[9]=l("p",null,"今天休息一天，还认识了一个骑车的南方人，他之前带的相机坏了，今天在城里又买了一个，我们约好明天一起走，下午我去上网传了一些照片给家人看，晚上吃的是丁大姐牛杂汤，感觉很不错，明早还去吃，希望吃完后能变的更有劲，骑车上山不用推！晚上回去后大家一起往杯子里放葡萄糖和红糖，为明天爬4298米的折多山做准备，据说翻过去后景色会更美，可以在新都桥镇遥望到贡嘎雪山。很期待不过也对那35公里上山路有些畏惧...",-1)),i(d,{dir:"/images/biketotibet/20080507/"}),e[10]||(e[10]=l("h2",{id:"🌦-翻过折多山到达新都桥镇-5月8日",tabindex:"-1"},[o("🌦 翻过折多山到达新都桥镇（5月8日） "),l("a",{class:"header-anchor",href:"#🌦-翻过折多山到达新都桥镇-5月8日","aria-label":'Permalink to "🌦 翻过折多山到达新都桥镇（5月8日）"'},"​")],-1)),e[11]||(e[11]=l("p",null,[l("code",null,"折多山"),o(),l("code",null,"牦牛"),o(),l("code",null,"风马"),o(),l("code",null,"新都桥")],-1)),e[12]||(e[12]=l("p",null,"早上不到5点半大家就起来了，刚骑到丁大姐门口就看到那个南方人从对面骑过来，头戴红色安全帽，穿着带桔色反光条的衣服，最吸引我们的还是他车把上那个不到15厘米高的小三角架，他说那个是用来架摄象机的，这种方式我们还都没有想到过，当时觉得这人挺专业的，于是担心爬山时我们会拖后腿，我们一起吃完很补的牛杂汤后便上路了，一路全是上坡，一开始我们都是骑着走的，后来那个南方人总是下来推，而且还推的很慢，我们只能骑一段然后再下来等他，经常骑车的人都知道这样边骑边停比一直骑下去要累的多，大腿总是在刚刚适应完疲劳的感觉后又松驰下来，然后又得重新去适应，后来没过多久，就看到一辆皮卡从后面超过来，停在我们前面，原来这家伙打算一路搭车到几百公里外的巴塘县，道别后骑了没多久又看到一辆从身边开过的小货车，上面摆着3辆自行车，里面的人还在冲我们招手，我刚把手抬起来他们就已经消失在转弯处了。当我们骑到海拔3000多米的时候大家都有些反映，我和12有点头疼，高原只是觉得喘的比较厉害，其实还有一种高原反应的症状之前一直没听说过，今天算是知道了，我们的肚子就象高原上的那些袋装食品一样有些发涨。好在人不象包装袋那样是密封的，大家也顾不上尴尬，每隔一会就会有人翘起屁股放屁。今天还第一次看到了牦牛，除了毛多没啥特别的，我们在快骑到山顶时天突然开始下起冰雹，冰雹不大但量很多，就象是凝固后的雪花从天上砸落下来，打在脸上还是会有点疼，只能歪着头骑，大概下午3点时我们才到垭口，今天真的很不容易，用了9个小时才到这里，35公里的连续上坡路，海拔提升1800米，我们推车的时间比骑的要多，站在那里再回头看刚才走过的盘山路时心里又是另一种感觉，从成都到珠峰的这段路上似乎只有折多山垭口上才有白塔，塔四周全是经幡，当地人开车路过垭口时会向天空抛撒风马，这种风马都是用五种颜色的纸印制，其中蓝色表示蓝天，红色表示火焰，白色表示白云，绿色表示江河，黄色表示大地，纸中间印着骏马，背负“喷焰玛民”，象征着财运昌隆。骏马腹下是猛虎和雪狮，当地人将风马抛向高空，让风将风马带向远空，以祈求各方神灵保佑百姓风调雨顺、人畜平安。藏族人在精神上的这种追求和生活是让我一直羡慕但又得不到的，我们在山顶还遇到一队骑摩托去拉萨的人，大家一起合影后便开始下山，下山时风突然变的很大都要用力踩脚踏，车才会往前走，骑了没多久柏油路就消失了，全是坑坑洼洼的石子路，还把我买的Vaude牌的驮包颠坏了，就这质量打完折还敢卖五百多，太让人失望了，简单处理后便继续前进，在到新都桥的这段路上景色超级好，蓝天，白云，雪山，牦牛，草原，白塔，绿树，藏式的房屋和屋前的小河，这一切就象一幅画一样展现在我们面前，但因为天快黑了而且离目的地还有十多公里，路还很烂天还在下雨，所以大家都没怎么停下来拍照，就顾着赶路了，路上高原还摔了，好在速度不快，大概晚上7点多我们才到新都桥镇，这里也叫光影之都，是摄影家的天堂，也是抢劫摄影家者的天堂，川藏线另外一个比较有名的匪地就是海子山，我们在进镇之前看到前面一百多米处有几只大狗在路边闲逛，于是停下车直到它们离开后才进入小镇，小镇里建筑的风格跟之前住的地方完全不一样，房屋采用石料建造，而且朝阳，每座房屋的墙上开着三四扇窗户，窗户外面一圈用黑色的涂料涂抹，到了这里才让我们感觉到已经进入藏区，我们住的旅馆也是这样子的，不过房间内部还是跟之前住的地方没区别，房间在三层，每次走上去都喘的很明显，头还有点疼，其实最担心的是鼻子有点堵了，如果感冒了就会很麻烦，晚上连脸都没洗就早早躺下睡了，为了适应一下高反大家决定明天休息一天。",-1)),i(d,{dir:"/images/biketotibet/20080508/"}),e[13]||(e[13]=a("",6)),i(d,{dir:"/images/biketotibet/20080510/"}),e[14]||(e[14]=l("h2",{id:"🌤-在雅江休息-5月11日",tabindex:"-1"},[o("🌤 在雅江休息（5月11日） "),l("a",{class:"header-anchor",href:"#🌤-在雅江休息-5月11日","aria-label":'Permalink to "🌤 在雅江休息（5月11日）"'},"​")],-1)),e[15]||(e[15]=l("p",null,[l("code",null,"雅江"),o(),l("code",null,"百服宁"),o(),l("code",null,"休息")],-1)),e[16]||(e[16]=l("p",null,"一早起来那3个人跟我们说因为海子山经常有人被抢，所以他们决定要搭车通过海子山到巴塘，还问我们要不要一起，我们拒绝了，今天高原不太舒服头有点热，于是大家决定在这里休息一天，我用百服宁救了他，上午出去换了一家条件较好的旅店，住那就是因为看上他家那个29寸的大电视，之后在哪个城市也没看到过这么大的。",-1)),i(d,{dir:"/images/biketotibet/20080511/"}),e[17]||(e[17]=l("h2",{id:"☀️🌨-翻过剪子弯山到达119道班-5月12日",tabindex:"-1"},[o("☀️🌨 翻过剪子弯山到达119道班（5月12日） "),l("a",{class:"header-anchor",href:"#☀️🌨-翻过剪子弯山到达119道班-5月12日","aria-label":'Permalink to "☀️🌨 翻过剪子弯山到达119道班（5月12日）"'},"​")],-1)),e[18]||(e[18]=l("p",null,[l("code",null,"被狗追"),o(),l("code",null,"剪子弯山"),o(),l("code",null,"花粉过敏"),o(),l("code",null,"119道班")],-1)),e[19]||(e[19]=l("p",null,"记得小时候写日记时总是在日期后面写上“晴”或者是“雪”、“雨”，但最近一写就是“晴、冰雹、雨、大雪、大风”，多种气象都会在一天出现，所以我们在一天里会换好多次衣服，脱了穿穿了再脱，今天早上6点多从雅江出发，刚出县城没多久，发现路边的狗明显多了起来，我们还被追了一次，好在是刚出门大家都比较有劲，没让它们追上，今天要翻4659米高的剪子弯山，要骑连续30公里的上坡路，海拔提升2000米左右，但大家状态都不错，只休息了一次，并且没有推车，由于天气很冷，早上我们往瓶子里倒的开水还没有来的及喝多少就已经变得冰凉冰凉的，后来我们喝凉水时都是先在嘴里把水弄温后再咽下去，今天爬山时有位好心的藏族大妈给我们倒了些热水，大冷天里能喝上口热水在这时便成了一种奢侈的享受，很感激她，直到现在我们还是会想起那时她给我们往杯子里倒水的样子，我在据垭口还有一半路时发现自己的手臂起了很多小水泡，用手轻轻一碰就会破掉，心里有些担心，于是打算到了理塘后再去医院看看，之后骑了没多久便看到一支部队，他们穿过之字型的公路，以直线的方式爬山，我们在路边等他们上来后，便请他们的队医帮我看了下，被告知是花粉过敏，这时才放下心，大概1点多时我们到达垭口，我们总是以接近步行的速度上山，然后再以汽车式的速度下山，所以上山时就算天气特别冷我通常也只是穿着件短袖，到垭口后再把湿透的衣服换下来，然后把包里所有的衣服都穿上，可即使这样下山时还是会觉得冷，4点多时我们到达川藏线上在骑友圈里非常有名的119道班，今天要在这住一晚，这里之所以有名是因为对于骑车人来说几乎没有人可以在一天时间里翻过多座大山到达附近能够住宿的县城，119道班据说以前是不要钱的，后来又有人说要20，这次我们去时涨到40但是包括晚饭和早饭，道班大姐给我们做的晚饭很好吃，至少米饭比之前吃到的都好，晚上吃完饭想跟家里报个平安，道班工人说只有爬到房后的山坡上手机才会有信号，当我们爬到半山腰时天开始下冰雹，又不停的打雷，于是大家决定先下来，下来后没多久就开始下雨，又没多久雨停了开始下大雪，从来没见过这么大的雪花，不过又没多久雪就停了，晚上我们担心道班的被子不暖和，于是大家都睡在自己的睡袋里，之前12在床上一掀被子我们就知道他要放屁了，今天他把屁放在睡袋里又后悔，然后着急解睡袋拉锁的样子把我和高原笑坏了。",-1)),i(d,{dir:"/images/biketotibet/20080512/"}),e[20]||(e[20]=a("",3)),i(d,{dir:"/images/biketotibet/20080513/"}),e[21]||(e[21]=l("h2",{id:"🌦-翻过两个无名山口到达理塘县-5月14日",tabindex:"-1"},[o("🌦 翻过两个无名山口到达理塘县（5月14日） "),l("a",{class:"header-anchor",href:"#🌦-翻过两个无名山口到达理塘县-5月14日","aria-label":'Permalink to "🌦 翻过两个无名山口到达理塘县（5月14日）"'},"​")],-1)),e[22]||(e[22]=l("p",null,[l("code",null,"康巴汉子"),o(),l("code",null,"扎西德勒"),o(),l("code",null,"理塘")],-1)),e[23]||(e[23]=l("p",null,"早上一直在下雨，快10点时雨才小了一些，今天的路很轻松，只有35公里，翻两个山口就到理塘了，路上遇到好多带着红色英雄结的康巴汉子，我们一路说了无数遍扎西德勒，现在已经说得越来越标准，路上有很多藏族小孩遇到我们就会跑过来说“hello”，然后伸手要钱，我们都是微笑着绕过，后来我们就说，要是在路上遇到骑车的老外，一定得好好教育教育他，不要乱给钱。不过很可惜我们一个也没遇到，由于今年西藏314暴乱和512地震所以老外不许进藏。今天的天气还是老样子，一会晴一会雨，一会大风一会冰雹，不过当爬到第二个山口时，景色突然变的很漂亮，远处有几座大雪山，山顶挂着旗云，云层很厚压得又很低，大家都拍了不少照片，下坡时也是走走停停，在路上就能看到山下的理塘县，到县城入口后看到一个大牌楼儿，写着“世界高城理塘”，当时我们都以为这里真的是世界上最高的县城，但是在后来我们去过的很多县城海拔都比这里要高，比如阿里地区海拔4700米的改则县。",-1)),i(d,{dir:"/images/biketotibet/20080514/"}),e[24]||(e[24]=l("h2",{id:"☀️🌨-在理塘休息-5月15日",tabindex:"-1"},[o("☀️🌨 在理塘休息（5月15日） "),l("a",{class:"header-anchor",href:"#☀️🌨-在理塘休息-5月15日","aria-label":'Permalink to "☀️🌨 在理塘休息（5月15日）"'},"​")],-1)),e[25]||(e[25]=l("p",null,[l("code",null,"理塘"),o(),l("code",null,"吃饺子"),o(),l("code",null,"12回家"),o(),l("code",null,"休息")],-1)),e[26]||(e[26]=l("p",null,"早上起来后发现外面在下大雪，于是再休息一天，中午在一东北人开的饺子馆里吃饺子，这些天来接触的不是藏族人就是四川人，能在这么偏远的地方看到东北人感觉还挺亲切，晚上我们在一家四川人开的饭馆里吃的饭，饭后跟老板聊了会，他说从理塘到巴塘的路挺危险的，有的藏族人大白天的都会拿着枪去抢东西，川藏线上往往是每10公里一个道班，但在这段路上道班却很少，后来听别处的道班工人说其实这段路以前有好几个道班，但是前几年一到晚上就总有好多人冲到道班里抢东西，所以就都撤掉了，这事要在内地是绝对不可能发生的，政府在处理包含民族纠纷这类事情时也挺头痛，公正不是向着他们也不是，看来老大也不是那么好当的，明天12就要回家了，他家里有事不得不回去，梦想才开始不到一半就要结束，心里的痛苦大家都能理解。",-1)),i(d,{dir:"/images/biketotibet/20080515/"}),e[27]||(e[27]=a("",3)),i(d,{dir:"/images/biketotibet/20080516/"}),e[28]||(e[28]=l("h2",{id:"☀️🌨-一路下坡到巴塘-5月17日",tabindex:"-1"},[o("☀️🌨 一路下坡到巴塘（5月17日） "),l("a",{class:"header-anchor",href:"#☀️🌨-一路下坡到巴塘-5月17日","aria-label":'Permalink to "☀️🌨 一路下坡到巴塘（5月17日）"'},"​")],-1)),e[29]||(e[29]=l("p",null,[l("code",null,"巴塘"),o(),l("code",null,"7碗米饭")],-1)),e[30]||(e[30]=l("p",null,"早晨起来后发现外面已经全部变成了白色，门口那只大狗看到我们出来后还是很精神的狂叫，听那个老警察说这狗除了他以外对谁都这样，我们早上随便吃了点东西便出发了，一路上经过6个隧道，隧道里面非常暗，打着车灯也得慢慢骑才成，要不路上有东西的话根本来不及避开，在其中一个隧道里骑的时候，突然斜对面一摩托车的灯亮了，一男人用不清楚的普通话问我们去哪里，有几个人，之前就听说那些打劫的人总是先这样问，于是我们便飞快的蹬了起来，那时根本顾不上地上会不会有坑或障碍物，不过好在我们运气不错，一路有惊无险，今天的路很轻松，70公里路几乎全是下坡，大概只用了3个小时我们就到巴塘了，中午吃了7碗米饭（米饭都是按人头算钱），吃完饭后在县城里转了转，感觉还没怎么走呢就把县城转遍了，虽然县城很小不过这里比理塘干净，规化的也很好，据当地人说这里之前地震过，后来重建的。",-1)),i(d,{dir:"/images/biketotibet/20080517/"}),e[31]||(e[31]=a("",3)),i(d,{dir:"/images/biketotibet/20080518/"}),e[32]||(e[32]=l("h2",{id:"🌤-翻过宗巴拉山到达芒康县-5月19日",tabindex:"-1"},[o("🌤 翻过宗巴拉山到达芒康县（5月19日） "),l("a",{class:"header-anchor",href:"#🌤-翻过宗巴拉山到达芒康县-5月19日","aria-label":'Permalink to "🌤 翻过宗巴拉山到达芒康县（5月19日）"'},"​")],-1)),e[33]||(e[33]=l("p",null,[l("code",null,"蓝雾"),o(),l("code",null,"猴子头骨"),o(),l("code",null,"宗巴拉山"),o(),l("code",null,"芒康")],-1)),e[34]||(e[34]=l("p",null,"早上睡到自然醒，快9点时从海通兵站出发，出兵站后没多久无意中回头发现后面的山都被蓝色的大雾摭住了，有些神秘的感觉，之前从来没见过这样的景色，后来还在路边的树枝上看到猴子的头盖骨，不知道是什么人挂在上面的，也不知道挂在上面有什么意义，我们没用多长时间就翻过了宗巴拉山口，12点左右就到芒康县了，这是进入西藏的第一个县，我们还是象往常一样先在县城里转了一圈然后选了一家位置不错的藏式宾馆住下，这家店规模挺大，但因为正在装修，所以才15一人，比较便宜，下午去网吧上网传了些照片还和几个藏族警察打了会CS，虐警察的感觉真爽，哈哈。",-1)),i(d,{dir:"/images/biketotibet/20080519/"}),e[35]||(e[35]=l("h2",{id:"☀️-翻过拉乌山到达竹卡-5月20日",tabindex:"-1"},[o("☀️ 翻过拉乌山到达竹卡（5月20日） "),l("a",{class:"header-anchor",href:"#☀️-翻过拉乌山到达竹卡-5月20日","aria-label":'Permalink to "☀️ 翻过拉乌山到达竹卡（5月20日）"'},"​")],-1)),e[36]||(e[36]=l("p",null,[l("code",null,"拉乌山"),o(),l("code",null,"澜沧江"),o(),l("code",null,"竹卡"),o(),l("code",null,"北斗七星")],-1)),e[37]||(e[37]=l("p",null,"早上从芒康出发，大概只骑了13公里上坡就到达海拔4388米的拉乌山口，景色很好，我们拍完照后便开始下山，下山路大概有33公里，路况很差，骑的比上山还累，路边是悬崖，下面是澜沧江，褐红色的江水流动很快，看起来很有气势，悬崖下澜沧江边还能看到几座小房子，离房子不远的山坡上有很明显的泥石流流过的痕迹，泥石流从山顶一直沿续到江边，敢在这附近建房子的一定是在这边生活了很多年的人，位置挑的这么准，我们骑了一段路后发现路边的山也由红色变成绿色了，川藏线上的每座大山给人的感觉都不一样，大概2点时过了一座桥后便到达竹卡，我们选择住在一家招待所里，虽然床上有很多土渣还有苍蝇屎，不过很便宜，才10元一人，下午躺床上睡了会，然后又调了下车，由于一路的颠簸，车上有些镙丝已经松了，后货架上的镙丝还没了，还好发现的不算太晚，于是我把备用的闸块当镙丝拧上去了，调好车后去隔壁小商店买东西时，有只大黄狗总围着我们转，当时我光着脚穿着凉鞋，它就总是闻我脚，后来听店老板说这狗只咬藏族人，也不知道是老板在开玩笑还是这狗不喜欢酥油茶的味道，晚上睡觉前在门口看了会星星，好久没看到过北斗七星了。",-1)),i(d,{dir:"/images/biketotibet/20080520/"}),e[38]||(e[38]=l("h2",{id:"☀️-翻过觉巴山到达荣许兵站-5月21日",tabindex:"-1"},[o("☀️ 翻过觉巴山到达荣许兵站（5月21日） "),l("a",{class:"header-anchor",href:"#☀️-翻过觉巴山到达荣许兵站-5月21日","aria-label":'Permalink to "☀️ 翻过觉巴山到达荣许兵站（5月21日）"'},"​")],-1)),e[39]||(e[39]=l("p",null,[l("code",null,"小孩推车"),o(),l("code",null,"觉巴山"),o(),l("code",null,"荣许兵站")],-1)),e[40]||(e[40]=l("p",null,"今天太阳暴晒，后背和脑袋都能摊鸡蛋了，我们今天一路沿着澜沧江爬山，随着海拔升高路也越来越险，路一边是悬崖，另一边的山上还总是掉石头，我的后轮就被击中了，好在石头不大，今天我又被蜜蜂盯上了，它总在我嘴边转来转去，可能是因为闻到我嘴里的糖味了，害的我虽然很累也不敢用嘴喘气，爬山时还有两个小孩帮我推车了，这几天有3，4个小孩都帮我推过车，高原很羡慕，哈哈，我们骑了26公里上坡路后才到达3908米的觉巴山垭口，拍了几张照后便开始下山，下坡时我们骑的很慢，路不好而且边上就是悬崖，大概3点多时到达登巴村，我们没有停留继续15公里上坡，计划今天住在荣许兵站，可是到了兵站后才发现这兵站里的人真不厚道，一张嘴就一人50，我们这一路住的标准间都没这么贵过，后来他说我们帮他补胎的话能便宜十元，只好答应下来，补完后他还想要我的补胎工具，这些当兵的人跟之前海通兵站里的战士比起来真的差太多了，他们把我们安排到一个铁皮房里住下，门没有锁，为了以防万一我们用桌子把门顶住，睡觉前想出去上个厕所，听高原说外面狗特多，我出去看了下门外，一排的小绿光啊，于是很无奈的找了个瓶子解决，晚上睡觉时把床上放的那两条被子都盖上了，也不知道这被子是用什么东西做的，压的我一宿都没翻过身。",-1)),i(d,{dir:"/images/biketotibet/20080521/"}),e[41]||(e[41]=l("h2",{id:"🌦-翻过东达山到达左贡-5月22日",tabindex:"-1"},[o("🌦 翻过东达山到达左贡（5月22日） "),l("a",{class:"header-anchor",href:"#🌦-翻过东达山到达左贡-5月22日","aria-label":'Permalink to "🌦 翻过东达山到达左贡（5月22日）"'},"​")],-1)),e[42]||(e[42]=l("p",null,[l("code",null,"东达山"),o(),l("code",null,"补胎"),o(),l("code",null,"左贡")],-1)),e[43]||(e[43]=l("p",null,"早上磨磨蹭蹭快10点才出发，25公里的连续上坡把我和高原都折磨的不行了，不过到了5008米高的东达山垭口时还是很兴奋，这是目前到过最高的地方，虽然标着是5008米，但近年来的多次测量证明东达山垭口足有5100米高，虽然东达山跟觉巴山一样荒凉，但是穿越东达山的公路相对来说算是好路了，尽管路面还是年代久远的碎石和土坏，但相对平缓，我把车停到路边后兴奋的爬到垭口边上的小山峰上，一开始爬的太快，喘的很厉害，心跳的也很快，后来调整了下速度还好一些，快到山顶时有一片雪地，本想从那走过去，伸条腿儿试探了一下，雪没到膝盖还没踩到底，就赶紧把腿抽出来了，山上的岩石都是一片一片的，踩在上面很滑，不过也挺有意思，途中还总能看到一些从来没有见过的植物还有彩色的石头，到山顶后发现景色比垭口处还美，能看到很远处的一群群雪山，不过山顶上的风也比垭口处更大了些，由于没穿外套于是没停留多久便开始下山，在山上走了好一会才到垭口，然后骑上车开始下山，下山时天开始下雨，我的车胎还扎了，磨胎时居然还磨错了地方，怀疑是高反在捣乱，高原反应有一种症状就是脑子会变的不好用，严重的人连基本的算术都做不到，是不是因为在最靠近天堂的地方不需要我们用脑子想太多事情，只要开心就好。",-1)),i(d,{dir:"/images/biketotibet/20080522/"}),e[44]||(e[44]=a("",3)),i(d,{dir:"/images/biketotibet/20080523/"}),e[45]||(e[45]=l("h2",{id:"🌦-头顶着乌云骑到邦达镇-5月24日",tabindex:"-1"},[o("🌦 头顶着乌云骑到邦达镇（5月24日） "),l("a",{class:"header-anchor",href:"#🌦-头顶着乌云骑到邦达镇-5月24日","aria-label":'Permalink to "🌦 头顶着乌云骑到邦达镇（5月24日）"'},"​")],-1)),e[46]||(e[46]=l("p",null,[l("code",null,"昌都"),o(),l("code",null,"邦达"),o(),l("code",null,"房间涂鸦")],-1)),e[47]||(e[47]=l("p",null,"早上9点半出门，今天的目的地是位于昌都地区的邦达镇，这里早在1995年时就建立了邦达机场，开辟了昌都至成都的空中航线，机场海拔4330米，是世界上最高、跑道最长的机场。虽然交通变的更方便了，只需要2个小时，不过一下子从成都飞到这四千多米的高原，不知道人会有怎样强烈的高原反应。今天太阳很足，但没有阳光的地方却还是感觉有些冷，下午下了会太阳雨，抬头看了一下，很明显的看到一块乌云在自己头顶，我们晚上快到邦达时遇到一个从河南徒步去拉萨的人，从他背后只能看到半截腿还有他的那个大背包，由于长时间走路，腿似乎都有些变形，晚上我们住在邦达的一家小旅店里，这家店的墙上被过往的游客写满了字，睡觉前我们还在房间里涂鸦，我画了个机器猫，还写下我是北京的风行并留下了QQ号，后来有一北京车友骑车路过这里并住在这个房间，还把我画的机器猫拍了下来然后发给我，看到照片后那种心情真是乱七八糟啊。",-1)),i(d,{dir:"/images/biketotibet/20080524/"}),e[48]||(e[48]=a("",3)),i(d,{dir:"/images/biketotibet/20080525/"}),e[49]||(e[49]=l("h2",{id:"🌤-翻过安久拉山到达然乌镇-5月26日",tabindex:"-1"},[o("🌤 翻过安久拉山到达然乌镇（5月26日） "),l("a",{class:"header-anchor",href:"#🌤-翻过安久拉山到达然乌镇-5月26日","aria-label":'Permalink to "🌤 翻过安久拉山到达然乌镇（5月26日）"'},"​")],-1)),e[50]||(e[50]=l("p",null,[l("code",null,"安久拉山"),o(),l("code",null,"磕长头"),o(),l("code",null,"然乌")],-1)),e[51]||(e[51]=l("p",null,"早上9点出发，今天一路顶风上坡，骑的腰和肩膀很累，裤子还磨破了，早上在路上遇到一队磕长头去拉萨的人，他们用身体丈量家乡与圣城之间的距离，这可能是天底下最虔诚的朝拜了，不少藏族人从千里之外一路磕长头至拉萨，为的只是一了朝圣的心愿，祈求神灵的保佑。我们互相扎西德勒后继续爬山，大概晚上7点时我们才到达海拔4385米高的安久拉山垭口，景色还不错，雪山前还有一个湖，天气很冷，拍完照后便开始下山，我们刚从成都出发后那些天最喜欢骑的路就是下坡路，因为速度很快也很轻松，但最近大家都不喜欢下坡了，就象今天这样，费这么大劲才爬到四千多米的位置，下个坡就降到二三千米处了，明天又得象今天这样爬山，对骑车的人来说，最在意的不是今天要爬海拔多少米的山，而是今天海拔要提升多少米，有的四千多米的山，我们只要骑2，3公里就到垭口了，但是有的不到四千米的山，却要爬30多公里坡才能到达垭口，川藏线就是这样，总是要不断的从二千多米提升到四千多米，然后又回到二千多米，进入然乌镇之前的一段盘山路上，因为这里总是不断塌方，养路的天路公司依山修建了一段“棚路”，巨大的水泥柱子排成了一道长廊，支撑起一段“防护棚”，塌方下来的土石被棚子接住，来往的车辆就在这段防护棚的保护下奔向魅力无穷的然乌湖。晚上8点多我们才到然乌镇，这里也是只有一条街，川藏公路穿城而过，路边只有饭馆和旅店，我们选择住在然乌宾馆，这的标准间50元一天，条件还不错。",-1)),i(d,{dir:"/images/biketotibet/20080526/"}),e[52]||(e[52]=l("h2",{id:"🌤-在然乌休息-5月27日",tabindex:"-1"},[o("🌤 在然乌休息（5月27日） "),l("a",{class:"header-anchor",href:"#🌤-在然乌休息-5月27日","aria-label":'Permalink to "🌤 在然乌休息（5月27日）"'},"​")],-1)),e[53]||(e[53]=l("p",null,[l("code",null,"然乌湖"),o(),l("code",null,"休息")],-1)),e[54]||(e[54]=l("p",null,"早上睡醒后躺在床上听歌，现在听《天路》跟以前听又是不一样的感觉，中午吃完饭后我们便骑着空车去看然乌湖，本以为骑空车上坡时会很轻松，可是感觉居然跟驮着包骑时差不多，只是推车时轻松很多，我们沿着去察隅的路骑了大概4，5公里就到湖边了，然乌湖畔如诗如画的景色一下子就让我们忘记了旅途的劳累，雪山，冰川，湖水，草场，白云，树林还有湖边藏家的小院子，看到这一切时会使人萌生起想要留在这里的冲动。我们拍了很多照片，我还在湖边捡了10块小石头，打算过段时间用珠峰的冰川融水把它们泡起来带回家，晚上回去后跟新认识的张雷聊了会，他也是骑车的，不过车骑到康定时就坏了，于是一段一段的搭车过来，明天我们尽量到波密，听说路不怎么样。",-1)),i(d,{dir:"/images/biketotibet/20080527/"}),e[55]||(e[55]=l("h2",{id:"🌤-沿着然乌湖到达波密县-5月28日",tabindex:"-1"},[o("🌤 沿着然乌湖到达波密县（5月28日） "),l("a",{class:"header-anchor",href:"#🌤-沿着然乌湖到达波密县-5月28日","aria-label":'Permalink to "🌤 沿着然乌湖到达波密县（5月28日）"'},"​")],-1)),e[56]||(e[56]=l("p",null,[l("code",null,"搓板路"),o(),l("code",null,"波密")],-1)),e[57]||(e[57]=l("p",null,"早上8点出发，前十多公里景色超级好，甚至好过之前在高尔寺山上看到的那群雪山，然乌湖水从然乌镇一直向波密方向流去，水的颜色也在慢慢变淡，我们在这十多公里停了无数次，总是骑一小段就忍不住下来拍照，在路上还遇到几个开车去拉萨的人，他们停下来拍完湖后还拍我们，后来有一次最离谱，我跟高原正在路边坐着吃东西，一辆车从山后拐弯上来后突然在我们面前停下来，我们还以为他有什么事，这时窗户打开了，然后就一阵咔嚓咔嚓，再然后话都没说就把车开走了，这时有点理解为什么有些藏族朋友会因为你拍到他或他家的牛而管你要钱，在没经人同意时就这样瞎拍的人确实挺讨厌的，不过有的藏族人很不地道，如果你拍到他的牛，他会按你照片里牛的数量来要钱，如果拍到牛群那你就要看看自己的钱包是不是有这么多钱了，往年曾有游客因为这种事情跟他们发生冲突，结果被捅死了，所以在藏区不要太肆意的去拍别人，不仅是礼貌还涉及到自己的安全问题，我们吃完东西后沿着湖水没骑多久就进入波密境内，柏油路也迅速消失，当时我们就觉得波密不怎么样啊，路都没人管，这段土路一共有40公里左右，有几段路特别不好走，中间是搓板路，两边是厚厚的松土，由于在松土上骑特别容易打滑而且很脏我们就选择在中间骑，车子一颠一颠的就象骑马一样，脑袋还不停的晃，骑过这段路后好不容易出现了柏油路，结果还开始变的顶风，风很大起码得有5、6级，我们都觉得今天到波密悬了，可进入山区后大山把风都挡住了，于是我们加快速度，高原在前面骑的特快，我用每小时40多公里的速度追他，晚上我们不到7点就到波密了，找到地方住后我们本来想去吃大盘鸡，问了几家店都是一百多元一盘，最后只好去吃别的，我们点了3个菜一共才花了43元，一样吃的很好，今天晚上还去网吧发照片了，这里的网吧是这一路上最贵的，5元一小时。",-1)),i(d,{dir:"/images/biketotibet/20080528/"}),e[58]||(e[58]=l("h2",{id:"🌧-穿过102天险到达通麦-5月29日",tabindex:"-1"},[o("🌧 穿过102天险到达通麦（5月29日） "),l("a",{class:"header-anchor",href:"#🌧-穿过102天险到达通麦-5月29日","aria-label":'Permalink to "🌧 穿过102天险到达通麦（5月29日）"'},"​")],-1)),e[59]||(e[59]=l("p",null,[l("code",null,"102天险"),o(),l("code",null,"通麦")],-1)),e[60]||(e[60]=l("p",null,"早上10点出发，今天下了一天雨，我们一路都是在树林中骑行，下坡时我们还把摩托车甩到了后面，高原一路上还总是吓唬路边的动物，之前吓过驴，今天吓过牛，猪还有狗，不同动物的反应也不一样，牛比较聪明，一吓就跑掉了，驴就比较笨了，吓得它一动不敢动，站在原地就呜...啊...呜啊的叫，今天下坡时高原还吓过一次狗，本来那狗趴在自己家门口没理我们，他冲狗叫了一声，那狗跟疯了似的就追我们，还好是在下坡，我们的速度都在40/km以上，所以那条狗跟本追不上，今天有段路被山上流下来的水淹没了，最深处估计有三十厘米深，我们谁都没下来推车过去，都是加快速度冲过去的，虽然鞋子是防水的，不过还是从上面灌进去了一些水，于是把袜子脱下来绑在驮包上然后换了双干的继续骑，下午快到通麦时天开始下小雨，路过102天险时心里还真有些担心，路边的山上有巨大的水泥护坡，在护坡上有许多巨大的钢筋锚钉头，这是为了稳定山体保护公路的措施，说明这里的地质确实是那种所谓“蠕动”状态的。我们骑时不敢离山太近也不敢离路边太近，一边有可能掉石头另一边是悬崖，我们这段路几乎都是在路中间骑，遇到车才靠边，明天到鲁朗的路上也有这样的路段，希望今天的雨不要下太久。",-1)),i(d,{dir:"/images/biketotibet/20080529/"}),e[61]||(e[61]=l("h2",{id:"🌦-穿过通麦天险到达鲁朗镇-5月30日",tabindex:"-1"},[o("🌦 穿过通麦天险到达鲁朗镇（5月30日） "),l("a",{class:"header-anchor",href:"#🌦-穿过通麦天险到达鲁朗镇-5月30日","aria-label":'Permalink to "🌦 穿过通麦天险到达鲁朗镇（5月30日）"'},"​")],-1)),e[62]||(e[62]=l("p",null,[l("code",null,"帕龙藏布江"),o(),l("code",null,"通麦天险"),o(),l("code",null,"鲁朗")],-1)),e[63]||(e[63]=l("p",null,"早上7点半出发，天一直在下小雨，今天目的地是鲁朗镇，藏语中的意思是“叫人不想家”的地方。出发前去厕所减重，这是我这辈子上过的最好的厕所，在厕所里就能看到外面的青山白云，山下就是帕龙藏布江，水流声很大，出发后骑出镇子没多久便看到一座大桥，这个桥完全是个软桥，就是在钢丝绳上铺板子做成的，桥头有武警战士控制车的通过次序。我们骑上去时一低头就能透过木板之间的缝隙看到下面滚滚的帕龙藏布江，今天会路过川藏线上很有名的通麦天险，其实这里是个气候宜人的地方，海拔只有1800多米，属于峡谷地段，丰富的雨水常常将谷地两侧的山石冲垮，所以泥石流和落石非常多，公路从修通开始就一直处于维修状态。路边经常能看到“限速5”的牌子，每隔一段路会有个较宽的路段用来汇车，有的坡很陡，上坡时只能用推的，下坡时往往不敢骑，路又窄又滑，而且边上就是悬崖，悬崖下面的帕龙藏布江水流很快，所以有时下坡我们也是推下去的，这段路上很多地段有明显塌过的迹象，路边也总是会有落下来的石头，大的足有3个枕头那么大，藏族朋友有个习惯，凡是有汽车或者人坠江的地方，都会沿绝壁悬挂上五彩经幡，以示对亡者的哀思和超度。我们一路上每隔一段或是在急弯的地方都能看到悬挂着或新或旧的经幡，我们出了天险路段后，路也变成了相当好的柏油路，于是擦了擦了链条又上了点油继续赶路，今天继续在林海中行进，快6点时到达鲁朗，鲁朗最出名的是林海还有墨脱石锅鸡。墨脱石锅是用一种叫做“皂石”的云母石砍凿而成，而这种石头只产于墨脱，要靠背夫从墨脱把原始石材背出来后，再由门巴族人用手工细心凿制，加工时要求下手力道匀称，一旦心急，皂石就会被凿穿，所以一般凿锅的多是门巴老人。墨绿色的云母石锅，保温性特别好，而且据说富含镁铁等17种矿物微量元素，鸡用的是当地的藏鸡，在鲁朗小镇上每家饭馆都主打这道菜，不过老板们几乎都是四川人，而且象这种小饭馆往往老板也兼职做厨师，菜的价格非常贵，要一百多块钱一锅，于是我们没有吃，只是要了三盘菜，10个馒头就解决了，吃完饭后又去买了些零食和水果，明天的目标是翻过色季拉山到林芝，如果运气好的话能在色季拉山垭口看到南迦巴瓦峰。南迦巴瓦是7000米级山峰中的最高峰，他巨大的三角形峰体终年积雪，云雾缭绕，从不轻易露出真面目。南迦巴瓦藏语的意思是“雪电如火燃烧”，这座山峰充满了神奇的传说，因为其主峰高耸入云，当地相传天上的众神时常会降临其上聚会和煨桑，我们看到的山顶的旗云就是神们燃起的桑烟，据说山顶上还有神宫和通天之路，因此居住在峡谷地区的人们对这座陡峭险峻的山峰都有着无比的推崇和敬畏。",-1)),i(d,{dir:"/images/biketotibet/20080530/"}),e[64]||(e[64]=a("",3)),i(d,{dir:"/images/biketotibet/20080531/"}),e[65]||(e[65]=a("",6)),i(d,{dir:"/images/biketotibet/20080602/"}),e[66]||(e[66]=l("h2",{id:"🌦-继续沿着尼洋河到松多镇-6月3日",tabindex:"-1"},[o("🌦 继续沿着尼洋河到松多镇（6月3日） "),l("a",{class:"header-anchor",href:"#🌦-继续沿着尼洋河到松多镇-6月3日","aria-label":'Permalink to "🌦 继续沿着尼洋河到松多镇（6月3日）"'},"​")],-1)),e[67]||(e[67]=l("p",null,[l("code",null,"尼洋河"),o(),l("code",null,"松多")],-1)),e[68]||(e[68]=l("p",null,"早上9点多出发，一路沿着尼洋河往上走，路边的村子也多了起来，房子都盖的很漂亮，6点多一点我们到达松多镇，这里只有一家汉族人开的招待所，一人15，我们住的房间是老板用木板和大塑料布在自家院子里架出来的，非常简陋，明天我们要翻海拔5013米的米拉山，这是到拉萨前的最后一座高山，过了这座山拉萨就没多远了。",-1)),i(d,{dir:"/images/biketotibet/20080603/"}),e[69]||(e[69]=l("h2",{id:"🌦-翻过米拉山到达墨竹工卡县-6月4日",tabindex:"-1"},[o("🌦 翻过米拉山到达墨竹工卡县（6月4日） "),l("a",{class:"header-anchor",href:"#🌦-翻过米拉山到达墨竹工卡县-6月4日","aria-label":'Permalink to "🌦 翻过米拉山到达墨竹工卡县（6月4日）"'},"​")],-1)),e[70]||(e[70]=l("p",null,[l("code",null,"米拉山"),o(),l("code",null,"萨嘎达瓦节"),o(),l("code",null,"墨竹工卡")],-1)),e[71]||(e[71]=l("p",null,"早上9点多出发，30公里上山路，其中20公里左右是缓坡，所以难度不大，到垭口之前，一辆大巴从后面开过，有一美女喊加油，顿时觉得全身充满了力量，正准备一口气骑到山顶，才发现已经看不到高原了，于是停下来等他，大概1点时我们就骑到了海拔5013米的米拉山垭口，照完相后坐在山口吃绿豆糕和花生米，这时一辆旅游大巴也来到了山口，游客下来后第一件事就是上厕所，然后就是拍照，不到半小时他们就上车下山了，当时我们都很庆幸没有以这种方式来西藏。晚上大概6点多时我们到达松赞干布的故乡墨竹工卡县，县城内街道很乱，城中的饭馆里苍蝇非常多，我们选了一家苍蝇较少的饭馆吃饭，今天是萨嘎达瓦节，据说是佛祖降生，成道，圆寂的日子，这段时间拉萨的八角街和林廓路应该会有很多人去转经，我们也打算明天到拉萨的八角街顺时针转一圈。",-1)),i(d,{dir:"/images/biketotibet/20080604/"}),e[72]||(e[72]=a("",3)),i(d,{dir:"/images/biketotibet/20080605/"}),e[73]||(e[73]=l("h2",{id:"🌤-参观大昭寺-6月6日",tabindex:"-1"},[o("🌤 参观大昭寺（6月6日） "),l("a",{class:"header-anchor",href:"#🌤-参观大昭寺-6月6日","aria-label":'Permalink to "🌤 参观大昭寺（6月6日）"'},"​")],-1)),e[74]||(e[74]=l("p",null,[l("code",null,"大昭寺"),o(),l("code",null,"矮房子酒吧"),o(),l("code",null,"青稞啤酒")],-1)),e[75]||(e[75]=l("p",null,"早上8点多就醒了，高原出去吃早饭，我赖在被窝里看NBA，中午吃完饭后我们在城内沿着一条小路往大昭寺方向走，路边有卖唐卡的小店还有很多台球室，我们在小路上走了没多久就迷路了，之后又走了好久才找到大昭寺，买了张票便进去了，我们先上到3层，在这里能看到不远处的布达拉宫还有拉萨附近的雪山，拍了些照片后便下到一层去主殿，这座寺里最出名的是主殿“觉拉康”内供奉的释迦牟尼12岁等身像，正当我们奇怪他怎么显得那么胖时，听一个导游讲到，那是因为很多藏族人有钱后都会捐出一些钱给佛象贴金，贴的多了所以就这样了。在寺内参观时一定要顺时针转而且不能戴帽子，只有佛头顶才能加冠，我们从大昭寺里出来后又到附近的街道逛了逛，下午我去上网传了些照片，晚上给妈妈打了个电话，没想到我发完照片后不到半小时她就看过了，这段时间她总是在地图上看我在哪，从照片上看我的样子，聊了一会后我和高原便去布达拉宫广场看夜景，我们去的还是晚了一些，没拍到最美的时候，但也还不错，夜晚的布达拉宫还是很漂亮的，广场上还有音乐喷泉，晚上高原去上网弄博客，我在位于北京东路的矮房子酒吧写日记，矮房子空间不大，装修得很随意却充满韵味，据说这里曾经是十一世达赖父亲的房子，已经有150年历史了。现在木制的房梁上有店主画的藏式和尼泊尔式佛眼，纯木的凳子上随意摆放着柔软的尼泊尔靠垫，灯光透过桔色羊毛纸做的灯罩给人的感觉显得很古老而且温暖。很多人都是被门口招牌上的“这里有你寻找已久的音乐”这一行字给带进来的，酒吧以印度、尼泊尔、西藏的传统音乐为主，你可以一边品尝美味的青稞啤酒，一边享受异域风情的音乐。",-1)),i(d,{dir:"/images/biketotibet/20080606/"}),e[76]||(e[76]=l("h2",{id:"🌤-参观布达拉宫-6月7日",tabindex:"-1"},[o("🌤 参观布达拉宫（6月7日） "),l("a",{class:"header-anchor",href:"#🌤-参观布达拉宫-6月7日","aria-label":'Permalink to "🌤 参观布达拉宫（6月7日）"'},"​")],-1)),e[77]||(e[77]=l("p",null,[l("code",null,"布达拉宫"),o(),l("code",null,"打阿嘎"),o(),l("code",null,"酸奶坊")],-1)),e[78]||(e[78]=l("p",null,"早上快8点时起床，每次一休息，我都要睡到自然醒，高原一早就睡不着了，然后出去逛街吃早点，回来后会告诉我哪有好玩的，哪有好吃的，然后我们就去那转，早上我们吃完饭后就直奔布达拉宫，往年布达拉宫都是一票难求，一张票最高时抄到1500一张，而今年人一下子少的可怜，旅游景点人少对游客来说真的是很奢侈的享受，布达拉宫给我印象最深的是那些打阿嘎的人，他们用原始的方法修复布达拉宫的地板和房顶，很喜欢他们唱的歌和劳动时用木夯敲打地板时发出的声音，他们分两组，一组边唱边工作，然后休息一会，休息的时候另一组继续这样，如此反复...我就站在他们附近看着，直到他们都休息时才离开，布达拉宫里有除了六世达赖以外所有达赖的灵塔，布达拉宫虽然拒绝了六世，但他的诗歌却传遍了前藏，后藏，山南地区以及大江南北。在现有的灵塔中五世的最大，用了3吨多黄金包裹并镶嵌了两万多颗宝石，高14米，看着很壮观也很吸引人。我们出来后又顺时针绕布达拉宫一周，布宫四周有一圈转经筒，转经筒是藏传佛教寺院里教徒祈祷用的一种法物，筒一般用铜皮包裹，筒中间有轴，上下两端固定，可以不断的旋转，里面装有纸印经文，周围刻有“六字真言”，当地人转布达拉宫时通常都会转动外墙上的每一个经筒，这样就代表他们念了很多经，我们绕布宫转完一圈后在酸奶坊喝了一碗青稞酒味的酸奶，感觉不错，小店装饰的也很漂亮，喜欢酸奶坊和那的牦牛酸奶，但最喜欢的是酸奶坊墙上的那块玻璃，因为可以在它身上看到远处的雪山和蓝天，那种感觉就象看到了另一个世界。",-1)),i(d,{dir:"/images/biketotibet/20080607/"}),e[79]||(e[79]=l("h2",{id:"🌤-坐车去看纳木措-6月8日",tabindex:"-1"},[o("🌤 坐车去看纳木措（6月8日） "),l("a",{class:"header-anchor",href:"#🌤-坐车去看纳木措-6月8日","aria-label":'Permalink to "🌤 坐车去看纳木措（6月8日）"'},"​")],-1)),e[80]||(e[80]=l("p",null,[l("code",null,"念青唐古拉山"),o(),l("code",null,"纳木措"),o(),l("code",null,"日落")],-1)),e[81]||(e[81]=l("p",null,"早上6点起床坐车去海拔4718米的纳木措，一路沿青藏线向北，汽车翻过海拔5190米的那根拉山垭口后便看到了纳木措，湖水就象蓝宝石一样镶嵌在念青唐古拉山脚下，非常漂亮，纳木措是世界上海拔最高的咸水湖。也是西藏三大圣湖之一，被人们称为天湖纳木措，守护在她身旁的就是念青唐古拉山，他们不仅是西藏最引人注目的神山圣湖，而且还是生死相依的恋人，关于他们之间的传说也有很多不同的版本。我们下车后选择住在湖边的一家小旅馆里，放好行李后就迫不及待的走到湖边，在湖边看纳木措时会有到了海边的感觉，视觉非常开阔，之前随旅游车来的那些人只在这里停留了一个小时便回拉萨了，现在湖边只有我和几百米外的高原，我坐在湖边静静的看着远处的雪山还有湖水，不知道过了多久便躺在湖边的沙石上睡着了，醒来后换了个地方又坐了好久才回到住的地方，回去后才知道有个跟我们一起坐车来的游客高原反应挺严重的，路都走不稳，吃了点东西后又都吐出来了，天黑前被他的一个朋友送回拉萨了，我们还好，除了走快时有点喘没别的反应，吃完晚饭后回住的地方坐了一会便和另外两个驴友到湖边的小山包上看日落，在西藏即使是快下山的太阳也非常刺眼，根本无法直视，我们在那拍了很多照片，一直舍不得离开，当天空几乎完全变黑的时候我们才反应过来，于是借着月光下山回到了住处。",-1)),i(d,{dir:"/images/biketotibet/20080608/"}),e[82]||(e[82]=l("h2",{id:"🌤-离开纳木措回到拉萨-6月9日",tabindex:"-1"},[o("🌤 离开纳木措回到拉萨（6月9日） "),l("a",{class:"header-anchor",href:"#🌤-离开纳木措回到拉萨-6月9日","aria-label":'Permalink to "🌤 离开纳木措回到拉萨（6月9日）"'},"​")],-1)),e[83]||(e[83]=l("p",null,[l("code",null,"纳木措"),o(),l("code",null,"拉萨")],-1)),e[84]||(e[84]=l("p",null,"早上8点多起床，错过了日出，起床后带了点吃的去湖边坐着，吃饱后又在地上躺了好久，闭着眼听湖水的浪声感觉这里就象大海一样，但纳木措的水质要比大海好的多，从水上面能很清楚的看到水下的石头，时间很快便到了中午，我们搭乘一辆旅游客车回到了拉萨，晚上继续上网发照片，想让家里人能尽快看到我的照片和我一起分享这份感动。",-1)),i(d,{dir:"/images/biketotibet/20080609/"}),e[85]||(e[85]=l("h2",{id:"🌤-转过八角街去玛吉阿米吃藏餐-6月10日",tabindex:"-1"},[o("🌤 转过八角街去玛吉阿米吃藏餐（6月10日） "),l("a",{class:"header-anchor",href:"#🌤-转过八角街去玛吉阿米吃藏餐-6月10日","aria-label":'Permalink to "🌤 转过八角街去玛吉阿米吃藏餐（6月10日）"'},"​")],-1)),e[86]||(e[86]=l("p",null,[l("code",null,"巴扎文化手工艺"),o(),l("code",null,"八角街"),o(),l("code",null,"玛吉阿米")],-1)),e[87]||(e[87]=l("p",null,"中午起床后去布达拉宫西边的酸奶坊喝酸奶，之后又去北京东路附近的巴扎文化手工艺店看了看，虽然店里东西挺贵但都挺不错的，我还答应老板，等我有钱了一定到她家店里来，喜欢什么就买什么，晚上我们去八角街上的玛吉阿米吃藏餐，可是吃起来的感觉更象是西餐，这家店在北京和昆明都有分店，但不管它开到哪里，店的名声都不会有拉萨八角街这家店名气大，玛吉阿米这个名字出自六世达赖仓央嘉错的情诗，当年仓央嘉错与玛吉阿米相会的地方，就是八角街的那个土黄色小楼。在拉萨应该有很多看着不起眼但又很有故事的地方，就象矮房子酒吧，谁会想到那里曾是十一世达赖父亲的房子啊，晚上回到旅馆后我把地图册拆了，只把计划要去的地方留下来了，也算减重了，高原带的地图是那种大张的，他先是把西藏那曲部分减掉了，其余部分几乎每过一个县城就会撕一点，当我们到拉萨时，他的地图就只剩下珠峰和阿里这两部分了。",-1)),i(d,{dir:"/images/biketotibet/20080610/"}),e[88]||(e[88]=a("",9)),i(d,{dir:"/images/biketotibet/20080613/"}),e[89]||(e[89]=a("",3)),i(d,{dir:"/images/biketotibet/20080614/"}),e[90]||(e[90]=l("h2",{id:"🌤-轻松骑到日喀则-6月15日",tabindex:"-1"},[o("🌤 轻松骑到日喀则（6月15日） "),l("a",{class:"header-anchor",href:"#🌤-轻松骑到日喀则-6月15日","aria-label":'Permalink to "🌤 轻松骑到日喀则（6月15日）"'},"​")],-1)),e[91]||(e[91]=l("p",null,[l("code",null,"日喀则"),o(),l("code",null,"剪头"),o(),l("code",null,"乡巴佬饭馆")],-1)),e[92]||(e[92]=l("p",null,"早上10点从江孜出发，体力还不错，4点就到日喀则了，这个城市给我的感觉不如拉萨那么特别，建设得跟内地城市没有多大区别，我们在城内转了一圈后选择住在珠峰路上的一家宾馆，标准间50，屋内很干净，我们找住的地方时有个标准就是附近最好有网吧和超市，最好还要有好的饭馆，这样我们休息时就会很方便，我们洗完澡后把衣服也洗了，晚饭前去剪了个头，都说了鬓角给我留着，结果还是让她给推掉了，当时的脸看上去就是所有地方都是黑的，只有两边没有鬓角的地方是白的，走在路上时总感觉有人在看我，有点尴尬，之后晒了好多天，脸才变成一个颜色，晚上我们去珠峰路上的乡巴佬饭馆吃东西，这里菜做的味道很不错。",-1)),i(d,{dir:"/images/biketotibet/20080615/"}),e[93]||(e[93]=l("h2",{id:"🌤-参观扎什伦布寺-6月16日",tabindex:"-1"},[o("🌤 参观扎什伦布寺（6月16日） "),l("a",{class:"header-anchor",href:"#🌤-参观扎什伦布寺-6月16日","aria-label":'Permalink to "🌤 参观扎什伦布寺（6月16日）"'},"​")],-1)),e[94]||(e[94]=l("p",null,[l("code",null,"扎什伦布寺"),o(),l("code",null,"强巴佛")],-1)),e[95]||(e[95]=l("p",null,"早上9点起来看NBA，中午吃完饭后便去扎什伦布寺参观，在寺门口遭到一群小孩追着我要钱，当时感觉很无助，走了好久才摆脱掉，我们进入寺后在里面转了很久，印象最深的就是那座近30米高的强巴佛铜像，强巴佛其实就是内地佛教中的弥勒佛，他是藏传佛教三世佛中的未来佛。三世佛即过去佛燃灯古佛、现在佛释迦牟尼佛和未来佛强巴佛。据说强巴佛会在五十六亿六千万年后替代释迦牟尼佛成为佛祖，所以他在信徒心中的地位是很高的，我们在寺内还看到有的信徒在佛像前供了一元钱，然后又找回了9毛，其实在当地很多人都是这样做的，一般寺院里还会有换零钱的地方，信徒会根据自己的经济实力及不同佛在自己心中的地位去供钱，我们不懂这些，所以通常就是把身上的零钱拿出来全部供上，在去扎什伦布寺之前妈妈还说让我有机会的话请班禅大师摸摸我的头，可是跟寺里的喇嘛一打听才知道人家现在在北京呢，而且很少回来。",-1)),i(d,{dir:"/images/biketotibet/20080616/"}),e[96]||(e[96]=a("",6)),i(d,{dir:"/images/biketotibet/20080618/"}),e[97]||(e[97]=l("h2",{id:"🌧🌨-翻过嘉措拉山到达白坝乡-6月19日",tabindex:"-1"},[o("🌧🌨 翻过嘉措拉山到达白坝乡（6月19日） "),l("a",{class:"header-anchor",href:"#🌧🌨-翻过嘉措拉山到达白坝乡-6月19日","aria-label":'Permalink to "🌧🌨 翻过嘉措拉山到达白坝乡（6月19日）"'},"​")],-1)),e[98]||(e[98]=l("p",null,[l("code",null,"嘉措拉山"),o(),l("code",null,"74/km"),o(),l("code",null,"冰雹"),o(),l("code",null,"白坝乡")],-1)),e[99]||(e[99]=l("p",null,"早上9点多吃完早饭便出发了，出拉孜县后没多久便开始翻海拔5246米的嘉措拉山，今天的路坡很陡而且还顶风，大家骑的非常累，中午吃东西时，建强从包里拿出了一个卷心菜还有一个大白萝卜，之后我和高原的饮食习惯也随着他发生了变化，我们把包里的沙琪玛绿豆糕都换成了大萝卜和黄瓜，又便宜又补充维生素。我们四个人爬山时都各有特点，高原虽然骑的不快，听他说最慢时速度才4/km，但他耐力很强，在好几个小时的爬山过程中他都不用停下来休息，胖子由于是是坐飞机到拉萨后才开始骑的，爬山过程中有点高反，所以爬山时总是骑一会就得下来推车，但他行李很少，只有一个背包，所以他总是不走公路，推着空车抄近路上山，我和建强属于爆发力强的那种，总是以9/km左右的速度上山，但也总是骑一段就下来休息一会，后来高原第一个到达垭口，在那等了我们一个小时后我们才在快5点时骑到那里，快到垭口时还有藏族司机给我们矿泉水喝，我们在嘉措拉山垭口照完相后便开始下山，今天又破记录了，我下山时最高速度74/km，正在窃喜时，胖子从我身边一闪而过，我在后面看着他狂蹬的样子楞了一下，后来听他说他下山时速度都快到90了，真是艺高人胆大啊。我们骑了没多久便开始下冰雹，这是我们一路上遭遇到的最大个的冰雹，得有花生米那么大，冰雹砸在自行车上发出铛铛的声音，很好听，不过打在身上时就有些疼了，好在下了没多久便停了，我们晚上快8点才到白坝乡，然后找地方住下后便去吃饭，吃完饭后去买珠峰大本营的门票，一张180，买之前我们还仔细研究了一下不买票应该怎么进去，不过风险较高还是放弃了，珠峰大本营的门票只有在这里才能买得到，大概10公里外的检票处不卖票，如果不知道的话就只能从那返回来买，开车的人还好说，如果是骑车的就会比较郁闷了。",-1)),i(d,{dir:"/images/biketotibet/20080619/"}),e[100]||(e[100]=a("",3)),i(d,{dir:"/images/biketotibet/20080620/"}),e[101]||(e[101]=l("h2",{id:"🌤-一路缓上坡到达珠峰大本营-6月21日",tabindex:"-1"},[o("🌤 一路缓上坡到达珠峰大本营（6月21日） "),l("a",{class:"header-anchor",href:"#🌤-一路缓上坡到达珠峰大本营-6月21日","aria-label":'Permalink to "🌤 一路缓上坡到达珠峰大本营（6月21日）"'},"​")],-1)),e[102]||(e[102]=l("p",null,[l("code",null,"摔车"),o(),l("code",null,"绒布寺"),o(),l("code",null,"珠峰大本营"),o(),l("code",null,"星空")],-1)),e[103]||(e[103]=l("p",null,"早上7点多出发，今天的路虽然只有52公里，但这52公里全是石子路而且几乎是一路缓上坡，我们骑的一点都不轻松，高原由于昨天摔伤了膝盖，现在只能一条腿发力，我们骑的很慢，刚出门没多久后就能远远的看到珠峰了，虽然只露出了一点点，但也让我们很兴奋，骑到下午时我又摔了一次，我顺着汽车压过的痕迹高速下坡，可是下了没一会儿这一小段路也变成厚厚的石子路了，车一打滑我就飞出去了，这次几乎是横着从车上飞出去的，虽然穿着厚厚的抓绒，但胳膊还是摔破了，而且后背也摔破了，连头上戴着的帽子都震歪了，我正了一下帽子然后坐在地上缓了好一会才把车扶到路边，然后往胳膊上洒了点酒精后继续骑，当我们过了绒布寺后便开始刮大风，估计最少也得有6级，当骑车的速度降到只有每小时3公里的时候我们便下车然后一路推上去，大概7点时我们到达大本营，云把珠峰完全挡住了，山东的两个朋友打算一会儿就离开这里，不在大本营过夜，他们一个要去樟木一个要去云南，我和高原则决定留在这里，一定要看到珠峰后再离开，晚上大概不到9点的时候珠峰就渐渐露出来了，太阳落山时珠峰顶上一片金黄，非常漂亮，连边防战士都说我们运气好，就在前几天这里还一直下雨什么都看不到，我们晚上住在边防战士的铁皮房里，睡的是登山队员用过的睡袋，睡袋温标好象是-30度的，躺在里面特别暖和，晚饭我们吃的是午餐肉还有方便面和鸡蛋，还有大白萝卜，这是我们这几天吃过最好的一顿，晚上睡觉前高原出去上厕所，然后没多久就兴奋的跑回来把我也叫了出去，抬头一看才发现珠峰大本营的夜空出奇的美，满天密密麻麻的全是星星，非常亮，我们在那傻乐着看了好久才回去睡觉。",-1)),i(d,{dir:"/images/biketotibet/20080621/"}),e[104]||(e[104]=l("h2",{id:"🌤-离开珠峰大本营-6月22日",tabindex:"-1"},[o("🌤 离开珠峰大本营（6月22日） "),l("a",{class:"header-anchor",href:"#🌤-离开珠峰大本营-6月22日","aria-label":'Permalink to "🌤 离开珠峰大本营（6月22日）"'},"​")],-1)),e[105]||(e[105]=l("p",null,[l("code",null,"珠峰大本营"),o(),l("code",null,"绒布冰川"),o(),l("code",null,"日喀则")],-1)),e[106]||(e[106]=l("p",null,"早上起床后发现珠峰已经从云中完全露出来了，我们坐在地上边听歌边看珠峰，就这样一直坐到中午才准备离开，今天打算骑到扎西宗乡然后搭车回日喀则，在接下来的路程里我们会坐车去阿里转神山然后再去新疆吃烤肉，在离开大本营前我们都灌了半瓶绒布冰川融水，又捡了几颗小石头做为纪念，下山的这50公里路我们骑的很小心，快7点时到达扎西宗乡后便坐在路边等车，运气很好，等了不到一小时便搭上一辆去日喀则的小皮卡，当车爬到嘉乌拉山垭口时，我们在这里再次看到了珠峰，似乎在远处才能看出她的高大，在珠峰大本营看时完全感觉不出来这是一座八千多米的山峰，只是觉得很漂亮而已，我们在垭口没有停留，翻过嘉乌拉山后又翻过了嘉措拉山和措拉山，于晚上1点多到达日喀则，我们还是住在老地方，和店老板聊了几句后便回屋睡觉去了。",-1)),i(d,{dir:"/images/biketotibet/20080622/"}),e[107]||(e[107]=l("hr",null,null,-1)),e[108]||(e[108]=l("p",null,"写到这里，故事并未结束，我们在日喀则将自行车邮寄回家，然后回到拉萨一起坐上班车经过三天四夜的颠簸来到阿里转山，在连续徒步28小时艰难完成转山后离开西藏，我们搭车来到新疆喀什吃烤肉，高原在这里住了三天就回家了，我又继续住了一周后便离开这里，经阿克苏、库尔勒、乌鲁木齐来到北疆的布尔津，然后骑了三天马经禾木后到达小时候从电视散文里看到的喀纳斯，一个人的旅行越到最后越觉得无聊，于是便提前结束行程，沿兰州、西安于2008年8月8日奥运会那天回到家里。",-1)),i(d,{dir:"/images/biketotibet/2008/"})])}const A=t(u,[["render",s]]);export{x as __pageData,A as default};
